import{_ as e,c as a,o as t,a as _}from"./app.015fbf38.js";const m='{"title":"\u55AE\u8ECA\u7684\u82B1\u9F13\u6EFE\u73E0\uFF0C \u4E00\u822C\u53EF\u4EE5\u7528\u591A\u4E45","description":"","frontmatter":{},"headers":[],"relativePath":"Bike/BikeInfo/\u55AE\u8ECA\u7684\u82B1\u9F13\u6EFE\u73E0\uFF0C \u4E00\u822C\u53EF\u4EE5\u7528\u591A\u4E45.md","lastUpdated":1648513476161}',r={},p=_('<h1 id="\u55AE\u8ECA\u7684\u82B1\u9F13\u6EFE\u73E0\uFF0C-\u4E00\u822C\u53EF\u4EE5\u7528\u591A\u4E45" tabindex="-1">\u55AE\u8ECA\u7684\u82B1\u9F13\u6EFE\u73E0\uFF0C \u4E00\u822C\u53EF\u4EE5\u7528\u591A\u4E45 <a class="header-anchor" href="#\u55AE\u8ECA\u7684\u82B1\u9F13\u6EFE\u73E0\uFF0C-\u4E00\u822C\u53EF\u4EE5\u7528\u591A\u4E45" aria-hidden="true">#</a></h1><h6 id="tags-\u516C\u8DEF\u8ECA" tabindex="-1">tags: <code>\u516C\u8DEF\u8ECA</code> <a class="header-anchor" href="#tags-\u516C\u8DEF\u8ECA" aria-hidden="true">#</a></h6><p><a href="https://www.mobile01.com/topicdetail.php?f=268&amp;t=5336583" target="_blank" rel="noopener noreferrer">Reference</a></p><p>Q: \u4E00\u822C\u82B1\u9F13\u662F\u6EFE\u73E0\u8EF8\u627F\uFF0C\u9760\u82B1\u9F13\u5916\u6BBC\u8207\u8EF8\u5FC3\uFF0C\u4E2D\u9593\u593E\u8457\u92FC\u73E0\u65CB\u8F49\u3002 \u56E0\u70BA\u82B1\u9F13\u5916\u6BBC\u8207\u8EF8\u5FC3\u5C31\u662F\u78E8\u640D\u9762\uFF0C\u53EA\u80FD\u7528\u5230\u78E8\u640D\u5230\u4E0D\u582A\u7528\u70BA\u6B62\uFF0C \u4E00\u822C\u82B1\u9F13\u4E0D\u662F\u5F88\u7CBE\u5BC6\uFF0C\u6CB9\u5C01\u6B62\u6F0F\u6548\u679C\u6709\u9650\uFF0C\u5FC5\u9808\u6CE8\u610F\u4E0A\u6CB9\u4FDD\u6301\u6F64\u6ED1\uFF0C\u6E1B\u5C11\u92C1\u8CEA\u6EFE\u73E0\u6E9D\u88AB\u78E8\u640D\u904E\u5EA6\u3002</p><p>\u5C0F\u5F1F\u9A0E\u55AE\u8ECA\u5F8C\u8F2A\u6709\u9593\u9699\u504F\u64FA\u60C5\u5F62\uFF0C \u5E38\u5E38\u8981\u82B1\u8D39\u5F88\u5927\u529B\u6C23\u9A0E\u4E58\uFF0C \u624D\u80FD\u9A0E\u7684\u52D5\uFF1F\u800C\u4E14\u6709\u91CD\u6258\u611F\uFF1F</p><p>A:</p><p>1.\u6E1B\u5C11\u92C1\u8CEA\u6EFE\u73E0\u6E9D\u88AB\u78E8\u640D\u904E\u5EA6? \u90A3\u662F\u4E0D\u92B9\u92FC\u6216\u935B\u9020\u92FC\uFF0C\u81EA\u884C\u8ECA\u8EF8\u627F\u7684\u96F6\u4EF6\u4E0D\u6703\u6709\u92C1\u5408\u91D1\u88FD\u7684 \u56E0\u70BA\u92C1\u5408\u91D1\u4E0D\u8010\u78E8\u4E0D\u8010\u58D3\uFF0C\u800C\u81EA\u884C\u8ECA\u8EF8\u627F\u9762\u5C0D\u7684\u78E8\u8017\u8DDF\u58D3\u529B\u4E26\u4E0D\u5C0F (\u5C31\u9023\u9676\u74F7\u57F9\u6797\u62FF\u4F86\u7528\u5728BB\u8DDF\u8F2A\u7D44\u5176\u5BE6\u90FD\u4E0D\u592A\u9069\u5408\uFF0C\u9019\u6771\u897F\u662F\u7528\u5728\u4F4E\u58D3\u9AD8\u8F49\u901F\u74B0\u5883)</p><p>2.\u8ACB\u554F\u662F\u55AE\u8ECA\u7684\u82B1\u9F13\u6EFE\u73E0\u58DE\u6389\u55CE\uFF1F \u9019\u662F\u6EFE\u73E0\u9810\u58D3\u4E0D\u8DB3\uFF0C\u767C\u751F\u7684\u539F\u56E0\u53EF\u80FD\u662F\u78E8\u640D\u7522\u751F\u7684\u9593\u9699\uFF0C\u4E5F\u53EF\u80FD\u662F\u9810\u58D3\u87BA\u7D72\u8DD1\u6389 \u91CD\u65B0\u9396\u9810\u58D3\u5C31\u80FD\u89E3\u6C7A\uFF0C\u82E5\u662F\u8F2A\u7D44\u4F7F\u7528\u5DF2\u4E45\u4E5F\u53EF\u8003\u616E\u6574\u7D44\u63DB\u65B0</p><p>3.\u4E00\u822C\u82B1\u9F13\u6EFE\u73E0\u7528\u591A\u4E45\u8981\u63DB\u6389\uFF1F \u6EFE\u73E0\u8F2A\u7D44\u4FDD\u990A\u4F7F\u7528\u5F97\u7576\uFF0C\u6B63\u5E38\u58FD\u547D\u6703\u67095\u842C\u516C\u91CC\u4EE5\u4E0A</p><p>4.\u9084\u662F\u8981\u63DB\u6574\u500B\u8F2A\u6846\u5462\uFF1F \u770B\u4F60\u56C9\uFF0C\u5927\u591A\u6578\u8ECA\u53CB\u90FD\u662F\u76F4\u63A5\u63DB\u65B0\u6574\u500B\u8F2A\u7D44 \u56E0\u70BA\u7576\u4F60\u7684\u8F2A\u7D44\u4F7F\u75285\u842C\u516C\u91CC\u4EE5\u4E0A\uFF0C\u715E\u8ECA\u908A\u5DF2\u7D93\u78E8\u5F97\u5DEE\u4E0D\u591A\uFF0C\u5E45\u689D\u4E5F\u5F88\u820A\u4E86 \u5E45\u689D\u5373\u4F7F\u6C92\u65B7\uFF0C\u4E5F\u6703\u6709\u61C9\u529B\u7D2F\u7A4D\u7684\u554F\u984C (\u92FC\u9435\u4E5F\u662F\u6709\u61C9\u529B\u7D2F\u7A4D\u554F\u984C\uFF0C\u53EA\u662F\u6C92\u92C1\u5408\u91D1\u90A3\u9EBC\u56B4\u91CD)</p><p>5.\u4E0A\u62CD\u8CE3\u7DB2\u7AD9\u641C\u5C0B\u5427 700C\u901A\u52E4\u8F2A\u7D441\u5343\u51FA\u982D\uFF0C26\u540B\u300120\u540B\u4E4B\u985E\u7684\u5E7E\u767E\u5143\u5C31\u6709 \u7AF6\u6280\u7B49\u7D1A\u7684\u8F2A\u7D44\u5C31\u6BD4\u8F03\u8CB4\u4E00\u4E9B</p>',11),o=[p];function n(s,c,d,i,h,l){return t(),a("div",null,o)}var u=e(r,[["render",n]]);export{m as __pageData,u as default};
